import React, { useEffect, useState } from 'react';
import { LayoutGrid, CloudSun, PlayCircle, Globe2 } from 'lucide-react';
import { BaseChart } from '../BaseChart';
import * as echarts from 'echarts';

export const GenericPreview: React.FC<{ comp: any }> = ({ comp }) => {
  const [mapLoaded, setMapLoaded] = useState(false);
  const [mapError, setMapError] = useState(false);

  useEffect(() => {
      if (comp.type === 'map') {
          // Use jsDelivr CDN for standard China GeoJSON
          fetch('https://cdn.jsdelivr.net/gh/mcuking/echarts-map-demo@master/map/china.json')
              .then(response => {
                  if (!response.ok) throw new Error('Network response was not ok');
                  return response.json();
              })
              .then(geoJson => {
                  echarts.registerMap('china', geoJson);
                  setMapLoaded(true);
              })
              .catch(err => {
                  console.error('Failed to load china map data', err);
                  setMapError(true);
              });
      }
  }, [comp.type]);

  switch (comp.type) {
    case 'chart':
      // Generate a generic mock chart based on name keywords
